from sympy import prime, factorint
from collections import Counter
def generate_primes_up_to_n(n):
    """Fast prime sieve to avoid calling prime() thousands of times."""
    sieve = [True] * (n + 1)
    for p in range(2, int(n**0.5) + 1):
        if sieve[p]:
            for i in range(p*p, n + 1, p):
                sieve[i] = False
    return [p for p in range(2, n + 1) if sieve[p]]
def get_lpf(num):
    """Returns the Largest Prime Factor (LPF) of a number."""
    if num < 2:
        return 0
    d = 2
    max_p = 2
    while d * d <= num:
        if num % d == 0:
            max_p = d
            while num % d == 0:
                num //= d
        d += 1
    if num > 1:
        max_p = num
    return max_p
def generate_A395951_sequence(N):
    # We need the first N-1 primes
    # Est. upper bound for the N-th prime using n*log(n) + n*log(log(n))
    import math
    if N < 6:
        estimated_max_prime = 15
    else:
        estimated_max_prime = int(N * (math.log(N) + math.log(math.log(N))))
    primes_list = generate_primes_up_to_n(estimated_max_prime)[:N]
    r_values = []
    # Paper specifies m >= 3
    for m in range(3, N + 1):
        n_m = primes_list[m - 2] + 1  # p_{m-1} + 1
        L_m = get_lpf(n_m)             # Largest prime factor
        if L_m > m:                    # Condition from OEIS A223881
            R_m = n_m // L_m
            r_values.append(R_m)
    # Count frequencies
    counts = Counter(r_values)
    # Sort by decreasing frequency, then by R_m value ascending
    sorted_r = sorted(counts.items(), key=lambda x: (-x[1], x[0]))
    return [item[0] for item in sorted_r]
